import{_ as i,c as a,o as e,aj as t}from"./chunks/framework.guNMSiFm.js";const c=JSON.parse('{"title":"Generating Cryptographic Keys","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security/generating-cryptographic-keys.md","filePath":"guide/security/generating-cryptographic-keys.md","lastUpdated":1777621302000}'),h={name:"guide/security/generating-cryptographic-keys.md"};function n(p,s,l,r,k,o){return e(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="generating-cryptographic-keys" tabindex="-1">Generating Cryptographic Keys <a class="header-anchor" href="#generating-cryptographic-keys" aria-label="Permalink to &quot;Generating Cryptographic Keys&quot;">​</a></h1><p>Use <code>kagami keys</code> to generate client, peer, and validator key material for the current Iroha 2 and Iroha 3 codebase.</p><h2 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h2><p>From the Iroha source checkout:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span></span></code></pre></div><p>JSON output is usually easiest to copy into TOML or automation:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>The command prints a public key and an exposed private key. Treat the private key as secret material; do not commit generated production keys.</p><h2 id="algorithms" tabindex="-1">Algorithms <a class="header-anchor" href="#algorithms" aria-label="Permalink to &quot;Algorithms&quot;">​</a></h2><p>Common algorithms are:</p><ul><li><code>ed25519</code> for client accounts, streaming identities, and most development networks.</li><li><code>secp256k1</code> when you need a secp256k1 account identity.</li><li><code>bls_normal</code> for validator consensus keys when the build enables BLS support.</li></ul><p>Check the exact algorithms supported by your build with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div><h2 id="deterministic-development-keys" tabindex="-1">Deterministic Development Keys <a class="header-anchor" href="#deterministic-development-keys" aria-label="Permalink to &quot;Deterministic Development Keys&quot;">​</a></h2><p>For reproducible fixtures, pass a seed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --seed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dev-alice&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>Seeds are private-key material. Use them only for local development and tests.</p><h2 id="bls-proofs-of-possession" tabindex="-1">BLS Proofs-of-Possession <a class="header-anchor" href="#bls-proofs-of-possession" aria-label="Permalink to &quot;BLS Proofs-of-Possession&quot;">​</a></h2><p>NPoS and Nexus validator profiles require BLS validator keys and PoPs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bls_normal</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>The JSON includes <code>pop_hex</code> when <code>--pop</code> is used. Use that value with the generated topology or <code>trusted_peers_pop</code> entries required by the profile.</p><h2 id="output-formats" tabindex="-1">Output Formats <a class="header-anchor" href="#output-formats" aria-label="Permalink to &quot;Output Formats&quot;">​</a></h2><p>Use the default output for terminal inspection, <code>--json</code> for automation, and <code>--compact</code> when another script needs plain line-oriented values:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --compact</span></span></code></pre></div><p>For full generated Kagami help:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha_kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> advanced</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> markdown-help</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> crates/iroha_kagami/CommandLineHelp.md</span></span></code></pre></div>',26)])])}const g=i(h,[["render",n]]);export{c as __pageData,g as default};
